import{_ as n,o,c as a,ag as h}from"./chunks/framework.BZohXCq9.js";const m=JSON.parse('{"title":"[Thiết kế Cơ bản] Module: Đặt chỗ & Thanh toán (Checkout Flow)","description":"","frontmatter":{},"headers":[],"relativePath":"05-quan-ly-sprint/sprint-6-dat-cho-thanh-toan/02-thiet-ke-co-ban.md","filePath":"05-quan-ly-sprint/sprint-6-dat-cho-thanh-toan/02-thiet-ke-co-ban.md"}'),i={name:"05-quan-ly-sprint/sprint-6-dat-cho-thanh-toan/02-thiet-ke-co-ban.md"};function e(l,t,r,s,g,c){return o(),a("div",null,[...t[0]||(t[0]=[h('<h1 id="thiet-ke-co-ban-module-đat-cho-thanh-toan-checkout-flow" tabindex="-1">[Thiết kế Cơ bản] Module: Đặt chỗ &amp; Thanh toán (Checkout Flow) <a class="header-anchor" href="#thiet-ke-co-ban-module-đat-cho-thanh-toan-checkout-flow" aria-label="Permalink to &quot;[Thiết kế Cơ bản] Module: Đặt chỗ &amp; Thanh toán (Checkout Flow)&quot;">​</a></h1><p>Tài liệu thiết kế cơ bản cho module Booking &amp; Payment, mô tả luồng đặt chỗ (Checkout Steps) và kiến trúc quy trình (Transaction Process).</p><h2 id="_1-luong-thanh-toan-checkout-steps-flow" tabindex="-1">1. Luồng Thanh toán (Checkout Steps Flow) <a class="header-anchor" href="#_1-luong-thanh-toan-checkout-steps-flow" aria-label="Permalink to &quot;1. Luồng Thanh toán (Checkout Steps Flow)&quot;">​</a></h2><h3 id="step-1-booking-information-thong-tin" tabindex="-1">Step 1: Booking Information (Thông tin) <a class="header-anchor" href="#step-1-booking-information-thong-tin" aria-label="Permalink to &quot;Step 1: Booking Information (Thông tin)&quot;">​</a></h3><ul><li><strong>Actor</strong>: Khách hàng.</li><li><strong>Quy trình</strong>: <ol><li>Chọn <strong>Ngày khởi hành</strong> (Calendar).</li><li>Chọn <strong>Số lượng khách</strong> (Adult/Children).</li><li>Nhập <strong>Họ tên</strong>, <strong>SĐT</strong>, <strong>Email</strong>.</li><li>Nhấn &quot;Tiếp tục&quot;.</li></ol></li><li><strong>Validation</strong>: Đảm bảo ngày chọn còn slot (Inventory check). SĐT/Email đúng định dạng regex.</li></ul><h3 id="step-2-order-summary-payment-tong-quan-thanh-toan" tabindex="-1">Step 2: Order Summary &amp; Payment (Tổng quan &amp; Thanh toán) <a class="header-anchor" href="#step-2-order-summary-payment-tong-quan-thanh-toan" aria-label="Permalink to &quot;Step 2: Order Summary &amp; Payment (Tổng quan &amp; Thanh toán)&quot;">​</a></h3><ul><li><strong>Actor</strong>: Khách hàng.</li><li><strong>Quy trình</strong>: <ol><li>Xem tóm tắt <strong>Tên tour</strong>, <strong>Ngày đi</strong>, <strong>Tổng tiền</strong>.</li><li>Nhập <strong>Mã giảm giá</strong> (nếu có).</li><li>Chọn <strong>Phương thức thanh toán</strong> (VNPay/MoMo/Chuyển khoản).</li><li>Nhấn &quot;Thanh toán ngay&quot;. Chuyển hướng tới Cổng thanh toán.</li></ol></li></ul><h3 id="step-3-payment-callback-result-ket-qua" tabindex="-1">Step 3: Payment Callback &amp; Result (Kết quả) <a class="header-anchor" href="#step-3-payment-callback-result-ket-qua" aria-label="Permalink to &quot;Step 3: Payment Callback &amp; Result (Kết quả)&quot;">​</a></h3><ul><li><strong>Actor</strong>: Hệ thống.</li><li><strong>Quy trình</strong>: <ol><li>Nhận tín hiệu (Call back) từ Cổng thanh toán.</li><li>Xử lý logic tại Backend.</li><li>Nếu Thành công -&gt; Hiển thị màn hình &quot;Đặt chỗ thành công&quot;. Gửi Email.</li><li>Nếu Thất bại -&gt; Hiển thị &quot;Thanh toán không thành công&quot; kèm hướng dẫn thử lại.</li></ol></li></ul><h2 id="_2-đac-ta-đieu-huong-navigation-logic" tabindex="-1">2. Đặc tả Điều hướng (Navigation Logic) <a class="header-anchor" href="#_2-đac-ta-đieu-huong-navigation-logic" aria-label="Permalink to &quot;2. Đặc tả Điều hướng (Navigation Logic)&quot;">​</a></h2><ul><li><strong>Back behavior</strong>: Nút quay lại tại Step 2 giữ nguyên các lựa chọn tại Step 1.</li><li><strong>Session management</strong>: Dữ liệu đặt chỗ được lưu vào Session/Local storage để tránh mất dữ liệu khi refresh trang.</li></ul><hr><p><em>Bản thiết kế sơ bộ bởi PO/BA cho Sprint 4.</em></p>',13)])])}const p=n(i,[["render",e]]);export{m as __pageData,p as default};
